import{_ as d,C as u,o,c as i,a2 as r,E as a,w as n,j as l}from"./chunks/framework.DIMps2S2.js";const g=JSON.parse('{"title":"余额通","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/cash-plus/cash-plus.md","filePath":"zh-CN/funds-and-wealth/cash-plus/cash-plus.md"}'),h={name:"funds-and-wealth/cash-plus/cash-plus.md"};function p(_,t,c,f,b,T){const e=u("TabItem"),s=u("Tabs");return o(),i("div",null,[t[2]||(t[2]=r('<h1 id="余额通" tabindex="-1">余额通 <a class="header-anchor" href="#余额通" aria-label="Permalink to &quot;余额通&quot;">​</a></h1><p>余额通是长桥的闲置资金增值服务，将账户内闲置资金自动投入货币市场基金，获取高于活期存款的收益，同时不影响股票交易。</p><h2 id="为什么需要余额通" tabindex="-1">为什么需要余额通 <a class="header-anchor" href="#为什么需要余额通" aria-label="Permalink to &quot;为什么需要余额通&quot;">​</a></h2><p><strong>问题</strong>：当你把钱存在长桥账户里等待交易机会时，这些现金闲置无法获利。银行活期存款利率极低。</p><p><strong>解决方案</strong>：余额通自动将闲置资金投入货币市场基金，利用你的空闲现金获取更高收益——同时保持完全的流动性：你可以随时提取这些资金用于买入股票，无需额外操作。</p><p><strong>核心优势</strong>：</p><ul><li>收益率<strong>远高于</strong>活期存款（约 3-5% 年化 vs 银行 0.3% 以下）</li><li><strong>完全自动</strong>——资金到账即自动转入，无需手动操作</li><li><strong>随时可用</strong>——卖出基金立即到账，不阻碍交易</li></ul><h2 id="各市场说明" tabindex="-1">各市场说明 <a class="header-anchor" href="#各市场说明" aria-label="Permalink to &quot;各市场说明&quot;">​</a></h2>',8)),a(s,{groupId:"cash-plus-region"},{default:n(()=>[a(e,{value:"hk",label:"香港余额通",default:""},{default:n(()=>[...t[0]||(t[0]=[l("table",{tabindex:"0"},[l("thead",null,[l("tr",null,[l("th",null,"项目"),l("th",null,"说明")])]),l("tbody",null,[l("tr",null,[l("td",null,"支持币种"),l("td",null,"港元（HKD）、美元（USD），每种各有三只货币基金可选")]),l("tr",null,[l("td",null,"起投金额"),l("td",null,"0.01")]),l("tr",null,[l("td",null,"自动转入时间"),l("td",null,"每个交易日 8:30")]),l("tr",null,[l("td",null,"可用操作"),l("td",null,"股票交易（立即可用），货币兑换和出金需等赎回到账")])])],-1),l("p",null,"开通并签署授权后，每个交易日 8:30 自动将闲置资金转入所选货币基金；买股票、换汇等扣款时自动赎回所需金额。可在设置中修改下次自动申购的基金，也支持手动申购。",-1),l("p",null,"手动赎回后 3 个自然日内不会自动转入。",-1)])]),_:1}),a(e,{value:"sg",label:"新加坡余额通"},{default:n(()=>[...t[1]||(t[1]=[l("table",{tabindex:"0"},[l("thead",null,[l("tr",null,[l("th",null,"项目"),l("th",null,"说明")])]),l("tbody",null,[l("tr",null,[l("td",null,"支持币种"),l("td",null,"新币（SGD）、美元（USD）")]),l("tr",null,[l("td",null,"起投金额"),l("td",null,"0.01")]),l("tr",null,[l("td",null,"自动转入时间"),l("td",null,"每天 10:00")]),l("tr",null,[l("td",null,"可用操作"),l("td",null,"股票交易、新股认购、换汇、出金（立即可用）")]),l("tr",null,[l("td",null,"收益周期"),l("td",null,"T 日 10:00 前转入 → T+1 确认份额 → T+2 派发收益")])])],-1),l("p",null,"签署授权后，每天 10:00 自动将闲置资金转入货币基金；买股票、认购新股等扣款时自动赎回。交易日 10:00 前提交手动赎回申请当日处理，手动赎回后 3 个自然日内不会自动转入。",-1)])]),_:1})]),_:1}),t[3]||(t[3]=r('<h2 id="关闭余额通" tabindex="-1">关闭余额通 <a class="header-anchor" href="#关闭余额通" aria-label="Permalink to &quot;关闭余额通&quot;">​</a></h2><p>关闭后，系统在最近交易日赎回持仓，最晚 T+1 到账。</p><p>香港账户：关闭后原余额通持仓转入普通基金账户；若账户有融资，购买力下降可能触发追缴保证金，请注意风险。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/how-to-enable-cash-plus">如何开通余额通</a></li><li><a href="/wiki/funds-and-wealth/idle-cash">闲钱理财</a></li><li><a href="/wiki/funds-and-wealth">基金与理财</a></li></ul>',5))])}const w=d(h,[["render",p]]);export{g as __pageData,w as default};
